import numpy as np
from app.strategy.base import BaseStrategy


class VaaBreadthV7(BaseStrategy):
    name = 'VAA_BREADTH_V7'
    multi_asset = True

    def generate_signals(self, data: dict) -> dict:
        all_syms = list(data.keys())
        first = all_syms[0]
        idx = data[first].index
        n = len(idx)

        result = {
            sym: pd.DataFrame({'signal': np.zeros(n), 'size_pct': np.zeros(n)}, index=idx)
            for sym in all_syms
        }

        rebal_freq = self.params.get('rebal_freq', 21)
        max_alloc = self.params.get('max_alloc', 0.95)
        vol_target = self.params.get('vol_target', 0.20)
        vol_period = self.params.get('vol_period', 63)
        top_n_equity = self.params.get('top_n_equity', 1)

        aggressive = [s for s in ['SPY', 'QQQ', 'EFA', 'IWM'] if s in data]
        defensive = [s for s in ['TLT', 'AGG', 'GLD'] if s in data]

        warmup = 252 + 10
        last_rebal = -rebal_freq
        cur_holdings = {}

        def get_vaa_score(sym, bar):
            if sym not in data or bar < 252:
                return None
            c = data[sym]['close']
            p0 = float(c.iat[bar])
            lbs = [21, 63, 126, 252]
            weights = [12, 4, 2, 1]
            score = 0.0
            for lb, w in zip(lbs, weights):
                if bar < lb:
                    return None
                p_past = float(c.iat[bar - lb])
                if p_past <= 0:
                    return None
                score += w * (p0 / p_past)
            return score

        def get_vol(sym, bar):
            if sym not in data or bar < vol_period + 1:
                return 0.15
            c = data[sym]['close']
            rets = c.iloc[bar - vol_period:bar].pct_change().dropna()
            if len(rets) < 10:
                return 0.15
            return max(float(rets.std() * np.sqrt(252)), 0.01)

        for bar in range(n):
            for sym in all_syms:
                result[sym]['signal'].iat[bar] = 1.0 if cur_holdings.get(sym, 0) > 0 else 0.0
                result[sym]['size_pct'].iat[bar] = float(cur_holdings.get(sym, 0.0))

            if bar < warmup or (bar - last_rebal) < rebal_freq:
                continue

            agg_scores = [(s, get_vaa_score(s, bar)) for s in aggressive]
            agg_scores = [(s, sc) for s, sc in agg_scores if sc is not None]

            def_scores = [(s, get_vaa_score(s, bar)) for s in defensive]
            def_scores = [(s, sc) for s, sc in def_scores if sc is not None]

            # Neutral VAA score when asset is flat: 12+4+2+1 = 19 (each ratio = 1)
            neutral_score = 19.0
            if agg_scores:
                n_positive = sum(1 for _, sc in agg_scores if sc > neutral_score)
                breadth = n_positive / len(aggressive)
            else:
                breadth = 0.0

            new_holdings = {}

            if breadth > 0 and agg_scores:
                agg_sorted = sorted(agg_scores, key=lambda x: x[1], reverse=True)
                top_eq = agg_sorted[:top_n_equity]

                eq_alloc = breadth * max_alloc
                def_alloc = (1.0 - breadth) * max_alloc

                for sym, _ in top_eq:
                    sym_vol = get_vol(sym, bar)
                    vol_scalar = min(vol_target / sym_vol, 1.0)
                    alloc_per = (eq_alloc / len(top_eq)) * vol_scalar
                    if alloc_per > 0.005:
                        new_holdings[sym] = new_holdings.get(sym, 0.0) + alloc_per

                if def_alloc > 0.005 and def_scores:
                    best_def = max(def_scores, key=lambda x: x[1])[0]
                    def_vol = get_vol(best_def, bar)
                    def_vol_scalar = min(vol_target / def_vol, 1.0)
                    new_holdings[best_def] = new_holdings.get(best_def, 0.0) + def_alloc * def_vol_scalar
            else:
                if def_scores:
                    best_def = max(def_scores, key=lambda x: x[1])[0]
                    def_vol = get_vol(best_def, bar)
                    vol_scalar = min(vol_target / def_vol, 1.0)
                    new_holdings[best_def] = max_alloc * vol_scalar

            total = sum(new_holdings.values())
            if total > max_alloc and total > 0:
                scale = max_alloc / total
                new_holdings = {s: v * scale for s, v in new_holdings.items()}

            for sym in all_syms:
                old = cur_holdings.get(sym, 0.0)
                new_val = new_holdings.get(sym, 0.0)
                if old > 0 and new_val == 0:
                    result[sym]['signal'].iat[bar] = -1.0
                elif new_val > 0:
                    result[sym]['signal'].iat[bar] = 1.0
                else:
                    result[sym]['signal'].iat[bar] = 0.0
                result[sym]['size_pct'].iat[bar] = float(new_val)

            cur_holdings = new_holdings.copy()
            last_rebal = bar

        return result
